case 'bubble':
  // Use first 3 numeric fields as x, y, z (bubble size) and 4th key for label
  const bubbleXKey = numericKeys[0] || keys[0];
  const bubbleYKey = numericKeys[1] || keys[1];
  const bubbleZKey = numericKeys[2] || keys[2];
  // Use string field for label, or numeric field if no string available
  const bubbleLabelKey = stringKeys[0] || numericKeys[3] || keys[3] || keys[0];

  // Calculate Y-axis domain with padding (20% above max value)
  const yValues = data.map((item) => Number(item[bubbleYKey]) || 0);
  const maxY = Math.max(...yValues);
  const minY = Math.min(...yValues);
  const yPadding = (maxY - minY) * 0.2 || maxY * 0.2 || 10;
  const yDomain = [Math.max(0, minY - yPadding), maxY + yPadding];

  // Calculate X-axis domain with padding
  const xValues = data.map((item) => Number(item[bubbleXKey]) || 0);
  const maxX = Math.max(...xValues);
  const minX = Math.min(...xValues);
  const xPadding = (maxX - minX) * 0.2 || maxX * 0.2 || 10;
  const xDomain = [Math.max(0, minX - xPadding), maxX + xPadding];

  // Custom label content renderer
  const customLabel = (props: any) => {
    const { x, y, value, index } = props;
    const labelValue = data[index]?.[bubbleLabelKey];

    if (!labelValue) return null;

    return (
      <text
        x={x}
        y={y}
        fill="#1f2937"
        textAnchor="middle"
        dominantBaseline="middle"
        fontSize="11"
        fontWeight="600"
      >
        {String(labelValue)}
      </text>
    );
  };

  return (
    <ResponsiveContainer width="100%" height={350}>
      <ScatterChart>
        <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
        <XAxis
          type="number"
          dataKey={bubbleXKey}
          name={bubbleXKey}
          stroke="#6b7280"
          domain={xDomain}
        />
        <YAxis
          type="number"
          dataKey={bubbleYKey}
          name={bubbleYKey}
          stroke="#6b7280"
          domain={yDomain}
        />
        <ZAxis
          type="number"
          dataKey={bubbleZKey}
          range={[60, 400]}
          name={bubbleZKey}
        />
        <Tooltip
          cursor={{ strokeDasharray: '3 3' }}
          contentStyle={{ backgroundColor: '#fff', border: '1px solid #e5e7eb', borderRadius: '6px' }}
        />
        <Legend />
        <Scatter
          name={endpointName}
          data={data}
          fill="#3B82F6"
        >
          <LabelList
            dataKey={bubbleLabelKey}
            position="center"
            content={customLabel}
          />
        </Scatter>
      </ScatterChart>
    </ResponsiveContainer>
  );
